    if (uc_op_r27) regs[27] <= s_fmul_68b24f7b_0_y0;
    case (uc_op_r28)
        2'd1: regs[28] <= s_fadd_9eba50d4_0_y0;
        2'd2: regs[28] <= s_fmul_68b24f7b_0_y0;
    endcase
    case (uc_op_r29)
        2'd1: regs[29] <= s_fmul_68b24f7b_0_y0;
        2'd2: regs[29] <= s_fadd_9eba50d4_0_y0;
    endcase
    case (uc_op_r30)
        2'd1: regs[30] <= s_fadd_9eba50d4_0_y0;
        2'd2: regs[30] <= s_fmul_68b24f7b_0_y0;
    endcase
    if (uc_op_r31) regs[31] <= s_fadd_9eba50d4_0_y0;
    if (uc_op_r32) regs[32] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r33) regs[33] <= s_fadd_9eba50d4_0_y0;
    if (uc_op_r34) regs[34] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r35) regs[35] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r36) regs[36] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r37) regs[37] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r38) regs[38] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r39) regs[39] <= s_fadd_9eba50d4_0_y0;
    if (uc_op_r40) regs[40] <= s_fmul_68b24f7b_0_y0;

    // Control and persistent state: the reset-gated registers.
    if (rst) begin
        pc            <= 0;
        err_pc_q      <= 0;
        transacting_q <= 0;
    end else begin
        pc <= next_pc;
        transacting_q <= (transacting_q << 1) | transacting_in;
        if (err) err_pc_q <= pc - FETCH_LAG;  // err wins; execution lags the fetch PC by FETCH_LAG, so step is pc-lag
        else if (in_ready && in_valid) err_pc_q <= 0;  // clear the diagnostic when a new transaction is accepted
    end
end

assign in_ready  = (pc == 0);
assign out_valid = (pc == LASTPC);  // result valid on PRESENT; execution lags the fetch by FETCH_LAG
assign err_pc    = err_pc_q;
assign out_0_0 = regs[5];
assign out_1_0 = regs[6];
assign out_2_0 = regs[14];
assign out_3_0 = regs[15];
assign out_4_0 = regs[16];
assign out_5_0 = regs[7];
assign out_6_0 = regs[0];
assign out_7_0 = regs[8];
assign out_8_0 = regs[17];

endmodule
